    <script>
        function resend_code(e, phone) {
            if ($(e).prop('disabled')) return false;
            $(e).attr('disabled', true);

            if (phone) {
                $.ajax({
                    url: '{{ route('send_code') }}',
                    type: 'POST',
                    dataType: 'json',
                    data: {
                        token: '{{ csrf_token() }}',
                        phone: phone
                    },
                    success: function (json) {
                        $(e).removeAttr('disabled');
                        $('#modal_login3 .alert').remove();

                        if (json.success) {
                            $('#modal_login3 [type="submit"]').before('<div class="alert alert-success">' + json.success + '</div>');
                        } else {
                            $('#modal_login3 [type="submit"]').before('<div class="alert alert-danger">' + json.error + '</div>');
                        }
                    }
                });
            }
        }

        $('#register_inn').on('change input', function(){
            if ($(this).val() > 11) {
                var options = {
                    method: "POST",
                    mode: "cors",
                    headers: {
                        "Content-Type": "application/json",
                        "Accept": "application/json",
                        "Authorization": "Token 9f50cc6bc6aa662e2b8a6574c80c9f519e05e25f"
                    },
                    body: JSON.stringify({query: $(this).val()})
                }

                fetch('https://suggestions.dadata.ru/suggestions/api/4_1/rs/findById/party', options)
                    .then(response => response.text())
                    .then(result => {
                        var suggestions = JSON.parse(result)['suggestions'][0]['data'];

                        if (typeof suggestions !== "undefined") {
                            var register_form = $('.register form');
                            var register_input = register_form.find('input');
                            var register_select = register_form.find('select');

                            register_input.each(function () {
                                var name = $(this).attr('name');

                                switch (name) {
                                    case 'kpp':
                                        if (typeof suggestions['kpp'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['kpp']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        break;
                                    case 'address':
                                        if (typeof suggestions['address']['unrestricted_value'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['address']['unrestricted_value']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        if (typeof suggestions['address']['data']['city'] !== "undefined") {
                                            $('.register [name="city"]').val(suggestions['address']['data']['city']);
                                        }

                                        if (typeof suggestions['address']['data']['postal_code'] !== "undefined") {
                                            $('.register [name="postcode"]').val(suggestions['address']['data']['postal_code']);
                                        }

                                        break;
                                    case 'address2':
                                        if (typeof suggestions['address']['unrestricted_value'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['address']['unrestricted_value']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        break;
                                    case 'ogrn':
                                        if (typeof suggestions['ogrn'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['ogrn']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        break;
                                    case 'firstname':
                                        if (typeof suggestions['fio']['name'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['fio']['name']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        break;
                                    case 'lastname':
                                        if (typeof suggestions['fio']['surname'] !== "undefined") {
                                            $('#register_' + name).val(suggestions['fio']['surname']);
                                            $('#register_' + name).parent().addClass('active');
                                        }

                                        break;
                                    default:
                                        break;
                                }
                            });

                            register_select.each(function () {
                                var name = $(this).attr('name');

                                switch (name) {
                                    case 'forma_sobstvennosti':
                                        if (typeof suggestions['opf']['short'] !== "undefined") {
                                            if (suggestions['opf']['short'] == 'ООО') {
                                                opf = 1;
                                            } else if (suggestions['opf']['short'] == 'ОАО') {
                                                opf = 2;
                                            } else if (suggestions['opf']['short'] == 'ПАО') {
                                                opf = 3;
                                            } else if (suggestions['opf']['short'] == 'ЗАО') {
                                                opf = 4;
                                            } else if (suggestions['opf']['short'] == 'АО') {
                                                opf = 5;
                                            } else if (suggestions['opf']['short'] == 'ИП') {
                                                opf = 6;
                                            } else {
                                                opf = 0;
                                            }

                                            if (opf) {
                                                $('#register_' + name).val(opf);
                                                $('#register_' + name).parent().find('.selectize li[data-value="' + opf + '"]').addClass('active');
                                                $('#register_' + name).parent().find('.selectize .select_value').text($('#register_' + name).parent().find('.selectize li[data-value="' + opf + '"]').text());
                                                $('#register_' + name).parent().addClass('active');
                                            }
                                        }

                                        break;
                                    case 'kontragent':
                                        if (typeof suggestions['type'] !== "undefined") {
                                            if (suggestions['type'] == 'INDIVIDUAL') {
                                                kontragent = 2;
                                            } else if (suggestions['opf']['short'] == 'LEGAL') {
                                                kontragent = 1;
                                            } else {
                                                kontragent = 0;
                                            }

                                            if (kontragent) {
                                                $('#register_' + name).val(kontragent);
                                                $('#register_' + name).parent().find('.selectize li[data-value="' + kontragent + '"]').addClass('active');
                                                $('#register_' + name).parent().find('.selectize .select_value').text($('#register_' + name).parent().find('.selectize li[data-value="' + kontragent + '"]').text());
                                                $('#register_' + name).parent().addClass('active');
                                            }
                                        }

                                        break;
                                    default:
                                        break;
                                }
                            });

                            $('#register_inn').parent().parent().find('.hide').fadeIn();
                            $('#register_inn').parent().parent().find('.register_fade').fadeOut(0);
                        } else {
                            $('#register_inn').parent().parent().find('.hide').fadeIn();
                            $('#register_inn').parent().parent().find('.register_fade').fadeOut(0);
                        }
                    })
                    .catch(error => {
                        $('#register_inn').parent().parent().find('.hide').fadeIn();
                        $('#register_inn').parent().parent().find('.register_fade').fadeOut(0);
                    });
            }
        });

        $(document).on('input change', '#login2_phone', function () {
            var val = $(this).val().replace(/[^+\d]/g, '');
            $('#login_code_phone').attr('value', val);
            var tel = val.substr(0, val.length - 4).replace(/[+\d]/g, '*');
            tel += this.value.substr(-4);

            $('.code_2').text(tel);
        });

        $(document).on('input paste', '.codes input', function () {
            if (this.value.length >= 4) {
                var text = this.value.slice(0, 4);
                $('.codes input:first').val(text[0]);
                $('.codes input:nth-child(2)').val(text[1]);
                $('.codes input:nth-child(3)').val(text[2]);
                $('.codes input:nth-child(4)').val(text[3]);
            } else if (this.value.length > 1) {
                this.value = this.value.slice(0, 1);
            } else if (this.value.length) {
                $(this).next().focus();
            }
        });
    </script>
